#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int N, M;
int **adj; // adjacency list stored as array of dynamic arrays
int *adjSize;
int *matchR; // match for right side, -1 if free
int *vis;

int dfs(int u) {
    for (int i = 0; i < adjSize[u]; ++i) {
        int v = adj[u][i];
        if (vis[v]) continue;
        vis[v] = 1;
        if (matchR[v] == -1 || dfs(matchR[v])) {
            matchR[v] = u;
            return 1;
        }
    }
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &N, &M);
        adj = (int **)malloc(N * sizeof(int *));
        adjSize = (int *)calloc(N, sizeof(int));
        // temporary storage for edges before we know each vertex degree
        int *tmpFrom = (int *)malloc(M * sizeof(int));
        int *tmpTo   = (int *)malloc(M * sizeof(int));
        for (int i = 0; i < M; ++i) {
            int A, B;
            scanf("%d %d", &A, &B);
            --A; --B;
            tmpFrom[i] = A;
            tmpTo[i] = B;
            adjSize[A]++;
        }
        for (int i = 0; i < N; ++i) {
            adj[i] = (int *)malloc(adjSize[i] * sizeof(int));
            adjSize[i] = 0; // will reuse as current fill index
        }
        for (int i = 0; i < M; ++i) {
            int u = tmpFrom[i];
            int v = tmpTo[i];
            adj[u][adjSize[u]++] = v;
        }
        free(tmpFrom);
        free(tmpTo);
        matchR = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) matchR[i] = -1;
        int matching = 0;
        vis = (int *)malloc(N * sizeof(int));
        for (int u = 0; u < N; ++u) {
            memset(vis, 0, N * sizeof(int));
            if (dfs(u)) matching++;
        }
        printf("%d\n", N - matching);
        for (int i = 0; i < N; ++i) free(adj[i]);
        free(adj);
        free(adjSize);
        free(matchR);
        free(vis);
    }
    return 0;
}

