import sys
sys.setrecursionlimit(1000000)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        g = [[] for _ in range(N)]
        for _ in range(M):
            A = int(next(it)) - 1
            B = int(next(it)) - 1
            g[A].append(B)
        matchR = [-1] * N
        def dfs(u, seen):
            for v in g[u]:
                if seen[v]:
                    continue
                seen[v] = True
                if matchR[v] == -1 or dfs(matchR[v], seen):
                    matchR[v] = u
                    return True
            return False
        matching = 0
        for u in range(N):
            seen = [False] * N
            if dfs(u, seen):
                matching += 1
        out_lines.append(str(N - matching))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

